const body = $input.first().json.body || $input.first().json;
const user_id = body.user_id || null;
const workspace_id = body.workspace_id || null;
const tool_key = body.tool_key || body.tool || 'operator';
const model = body.model || 'claude-sonnet-4-6';
const tokens_in = Number(body.tokens_in || body.input_tokens || 0);
const tokens_out = Number(body.tokens_out || body.output_tokens || 0);
const status = body.status || 'completed';
const duration_ms = Number(body.duration_ms || 0);
const session_id = body.session_id || null;
if (!user_id) throw new Error('user_id is required');
return [{ json: { user_id, workspace_id, tool_key, model, tokens_in, tokens_out, status, duration_ms, session_id, now: new Date().toISOString() } }];

